def _read_marker(data: bytes, index: int) -> tuple[int, int, bytes]:
    if data[index] != 0xFF:
        raise ValueError("Invalid JPEG marker.")
    marker = data[index + 1]
    if marker in (0xD8, 0xD9):
        return marker, index + 2, b""
    length = struct.unpack_from(">H", data, index + 2)[0]
    payload = data[index + 4 : index + 2 + length]
    return marker, index + 2 + length, payload

